/**
 * Templates for the logger recipe — types, levels, factory, singleton, barrel.
 */

function capitalize(s: string): string {
  return s.charAt(0).toUpperCase() + s.slice(1);
}

export function typesTemplate(name: string): string {
  return `/**
 * @generated by @flusk/cli
 * Logger configuration types
 */

export interface ${capitalize(name)}LoggerOptions {
  name?: string;
  level?: string;
  pretty?: boolean;
}
`;
}

export function levelsTemplate(): string {
  return `/**
 * @generated by @flusk/cli
 * Log level constants
 */

export const LOG_LEVELS = {
  fatal: 60,
  error: 50,
  warn: 40,
  info: 30,
  debug: 20,
  trace: 10,
} as const;

export type LogLevel = keyof typeof LOG_LEVELS;
`;
}

export function factoryTemplate(name: string): string {
  return `/**
 * @generated by @flusk/cli
 * Logger factory — creates a configured Pino instance
 */

import pino from 'pino';
import type { ${capitalize(name)}LoggerOptions } from './types.js';

export function createLogger(
  options: ${capitalize(name)}LoggerOptions = {},
): pino.Logger {
  const level = options.level
    || process.env.${name.toUpperCase()}_LOG_LEVEL
    || 'info';

  const pretty = options.pretty
    ?? process.env.NODE_ENV !== 'production';

  return pino({
    name: options.name || '${name}',
    level,
    ...(pretty
      ? { transport: { target: 'pino-pretty', options: { colorize: true } } }
      : {}),
  });
}
`;
}

export function singletonTemplate(): string {
  return `/**
 * @generated by @flusk/cli
 * Singleton logger instance
 */

import type pino from 'pino';
import { createLogger } from './create-logger.js';

let _instance: pino.Logger | null = null;

export function getLogger(): pino.Logger {
  if (!_instance) _instance = createLogger();
  return _instance;
}

export function setLogger(logger: pino.Logger): void {
  _instance = logger;
}

export function resetLogger(): void {
  _instance = null;
}
`;
}

export function barrelTemplate(): string {
  return `/**
 * @generated by @flusk/cli
 */

export { createLogger } from './create-logger.js';
export { getLogger } from './logger.js';
export type { FluskLoggerOptions } from './types.js';
export type { LogLevel } from './levels.js';
`;
}
